function renderClassSpellList(className) {
  const container = document.getElementById(`${className}-spell-list-container`);
  const data = CLASS_SPELLS[className];
  let html = '';

  for (const level in data) {
    html += `<h3 class="subsection-title">Level ${level}</h3>`;
    html += `<div style="display:grid; grid-template-columns: repeat(auto-fill, minmax(200px, 1fr)); gap:10px; margin-bottom:20px;">`;
    data[level].forEach(spellName => {
      html += `<div style="padding:10px; background:var(--bg-card); border:1px solid var(--border); border-radius:4px; font-size:0.9em; color:var(--gold-light);">${spellName}</div>`;
    });
    html += `</div>`;
  }
  container.innerHTML = html;
}

// renderSpells is called from spellbook.html tab buttons and oninput handlers

/* === script block 3 === */
function closeNav() {
    const nav = document.getElementById('main-nav');
    const toggle = document.getElementById('nav-toggle');
    if (!nav) return;
    nav.classList.remove('nav-open');

    // Release body scroll lock, restoring scroll position
    if (document.body.classList.contains('nav-is-open')) {
      const scrollY = parseInt(document.body.style.top || '0') * -1;
      document.body.classList.remove('nav-is-open');
      document.body.style.top = '';
      window.scrollTo(0, scrollY);
    }

    if (toggle) {
      toggle.classList.remove('open');
      toggle.setAttribute('aria-expanded', false);
      toggle.querySelector('.toggle-icon').textContent = '☰';
    }
  }

  function updateNavLabel(navEl) {
    const el = document.getElementById('nav-current-label');
    if (el && navEl) el.textContent = navEl.textContent.trim();
  }

  function setupHamburger() {
    const toggle = document.getElementById('nav-toggle');
    const nav = document.getElementById('main-nav');
    if (!toggle || !nav) return;

    toggle.addEventListener('click', () => {
      const isOpen = nav.classList.toggle('nav-open');
      if (isOpen) {
        // Lock page scroll — save current position in body.top
        const scrollY = window.scrollY;
        document.body.style.top = `-${scrollY}px`;
        document.body.classList.add('nav-is-open');
      } else {
        closeNav();
        return;
      }
      toggle.classList.toggle('open', isOpen);
      toggle.setAttribute('aria-expanded', isOpen);
      toggle.querySelector('.toggle-icon').textContent = isOpen ? '✕' : '☰';
    });

    // Close when a link is tapped
    nav.addEventListener('click', e => {
      if (e.target.tagName === 'A') closeNav();
    });

    // NOTE: We deliberately do NOT close the nav on scroll,
    // so mobile users can open the menu and scroll through all options.

    // Close when tapping outside
    document.addEventListener('click', e => {
      const wrapper = document.getElementById('nav-wrapper');
      if (wrapper && !wrapper.contains(e.target)) closeNav();
    });
  }

  document.addEventListener('DOMContentLoaded', setupHamburger);

  function showPage(pageId, navEl) {
    // Hide all sections
    document.querySelectorAll('.page-section').forEach(s => s.classList.remove('active'));
    // Show target
    document.getElementById('page-' + pageId).classList.add('active');
    // Update nav
    document.querySelectorAll('nav a').forEach(a => a.classList.remove('active'));
    if (navEl) { navEl.classList.add('active'); updateNavLabel(navEl); }
    // Close mobile menu
    closeNav();
    // Scroll to top
    window.scrollTo({ top: 0, behavior: 'smooth' });
    if (pageId === 'spellbook') renderSpells();
  }

