const MUT_CATS = {
  'positive': {color:'#2d7a4f', label:'✅ Beneficial'},
  'negative': {color:'#c0392b', label:'⚠️ Detrimental'},
  'major-negative': {color:'#7f0000', label:'💀 Severe'},
  'cosmetic': {color:'#7a6848', label:'👁 Cosmetic'},
  'mixed': {color:'#a07820', label:'🎲 Mixed'},
};

function renderMutations() {
  const search = document.getElementById('mut-search').value.toLowerCase();
  const cat = document.getElementById('mut-cat-filter').value;
  const container = document.getElementById('mutations-list');
  
  let filtered = MUTATIONS.filter(m => {
    if (search && !m.text.toLowerCase().includes(search) && !String(m.n).includes(search)) return false;
    if (cat !== 'all' && m.cat !== cat) return false;
    return true;
  });
  
  document.getElementById('mut-count').textContent = filtered.length + ' mutations';
  
  container.innerHTML = filtered.map(m => {
    const c = MUT_CATS[m.cat] || MUT_CATS['mixed'];
    return `<div style="display:flex;gap:10px;align-items:flex-start;padding:7px 10px;border-bottom:1px solid rgba(212,175,55,0.07);border-left:3px solid ${c.color}40;transition:background 0.1s;" onmouseover="this.style.background='rgba(212,175,55,0.04)'" onmouseout="this.style.background=''">
      <span style="font-family:Cinzel,serif;color:${c.color};font-size:0.8em;min-width:36px;text-align:right;padding-top:2px;">${m.n}</span>
      <span style="flex:1;font-size:0.88em;color:#c8b888;line-height:1.5;">${m.text}</span>
      <span style="background:${c.color}22;color:${c.color};font-size:0.65em;font-family:Cinzel,serif;padding:2px 7px;border-radius:8px;white-space:nowrap;align-self:center;">${c.label.replace(/^[^ ]+ /,'')}</span>
    </div>`;
  }).join('');
}

document.getElementById('mut-search').addEventListener('input', renderMutations);
document.getElementById('mut-cat-filter').addEventListener('change', renderMutations);
renderMutations();

function rollMutation() {
  const idx = Math.floor(Math.random() * MUTATIONS.length);
  const m = MUTATIONS[idx];
  const c = MUT_CATS[m.cat] || MUT_CATS['mixed'];
  const result = document.getElementById('roll-result');
  result.style.display = 'block';
  result.innerHTML = `<span style="font-family:Cinzel,serif;color:${c.color};font-size:1.1em;">🎲 Roll ${m.n}:</span> &nbsp;<strong style="color:#e8d5a0;">${m.text}</strong> &nbsp;<span style="background:${c.color}22;color:${c.color};font-size:0.72em;font-family:Cinzel,serif;padding:2px 8px;border-radius:8px;">${c.label}</span>`;
}
// Tab switching function
/* switchTab defined below */

// Global variable to track current class filter
let currentSpellClass = 'all';

// Filter spells by class
function filterSpellsByClass(className) {
  currentSpellClass = className;
  
  // For 'all' tab, handled by existing renderSpells
  if (className === 'all') {
    return;
  }
  
  const container = document.getElementById('spells-container-' + className);
  if (!container) return;
  
  // Define spell lists by class based on D&D spell access
  let filtered = [];
  
  switch(className) {
    case 'cleric':
      // Cleric gets: Abjuration, Conjuration, Divination, Necromancy, some Evocation
      filtered = SPELLS.filter(s => 
        ['abjuration', 'conjuration', 'divination', 'necromancy', 'evocation'].includes(s.school) &&
        !s.name.includes('Arcane') // Exclude arcane-specific spells
      );
      break;
      
    case 'druid':
      // Druid gets: Conjuration, Divination, Transmutation, nature spells
      filtered = SPELLS.filter(s => 
        ['conjuration', 'divination', 'transmutation'].includes(s.school) ||
        s.name.toLowerCase().includes('animal') ||
        s.name.toLowerCase().includes('plant') ||
        s.name.toLowerCase().includes('nature')
      );
      break;
      
    case 'mage':
      // Mage gets almost everything except divine spells
      filtered = SPELLS.filter(s => 
        !['Cure Wounds', 'Healing Word', 'Prayer of Healing', 'Mass Cure Wounds', 
          'Mass Heal', 'Heal', 'Greater Restoration', 'Lesser Restoration', 'Raise Dead',
          'Resurrection', 'True Resurrection', 'Revivify', 'Beacon of Hope', 'Death Ward',
          'Guardian of Faith', 'Spirit Guardians', 'Spiritual Weapon', 'Warding Bond',
          'Aid', 'Bless', 'Shield of Faith', 'Sanctuary', 'Guidance', 'Sacred Flame',
          'Spare the Dying', 'Speak with Dead', 'Commune', 'Divination'].includes(s.name)
      );
      break;
      
    case 'illusionist':
      // Illusionist specializes in Illusion but can use some other schools
      filtered = SPELLS.filter(s => 
        s.school === 'illusion' ||
        (s.school === 'enchantment' && s.level <= 3) ||
        (s.school === 'divination' && s.level <= 2)
      );
      break;
      
    case 'paladin':
      // Paladin gets divine spells up to level 4
      filtered = SPELLS.filter(s => 
        s.level <= 4 &&
        s.level >= 1 &&
        ['Cure Wounds', 'Healing Word', 'Lesser Restoration', 'Prayer of Healing',
         'Aid', 'Bless', 'Shield of Faith', 'Sanctuary', 'Protection from Energy',
         'Remove Curse', 'Beacon of Hope', 'Death Ward', 'Freedom of Movement',
         'Warding Bond', 'Detect Magic', 'Command', 'Zone of Truth'].includes(s.name)
      );
      break;
      
    case 'ranger':
      // Ranger gets nature spells up to level 3
      filtered = SPELLS.filter(s => 
        s.level <= 3 &&
        s.level >= 1 &&
        (['conjuration', 'divination', 'transmutation'].includes(s.school) ||
         s.name.toLowerCase().includes('animal') ||
         ['Cure Wounds', 'Speak with Dead', 'Detect Magic', 'Alarm'].includes(s.name))
      );
      break;
      
    case 'bard':
      // Bard gets a mix from multiple classes, mostly enchantment and illusion
      filtered = SPELLS.filter(s => 
        s.level <= 6 &&
        (['enchantment', 'illusion', 'divination', 'abjuration'].includes(s.school) ||
         ['Cure Wounds', 'Healing Word', 'Lesser Restoration'].includes(s.name))
      );
      break;
  }
  
  // Render the filtered spells
  const schoolColors = {
    abjuration:'#4a90d9', conjuration:'#9b59b6', divination:'#2ecc71',
    enchantment:'#e91e8c', evocation:'#e74c3c', illusion:'#8e44ad',
    necromancy:'#7f8c8d', transmutation:'#e67e22', '':'#d4af37'
  };
  
  container.innerHTML = filtered.map(s => {
    const col = schoolColors[s.school] || '#d4af37';
    const lvlLabel = s.level === 0 ? 'Cantrip' : 'Level ' + s.level;
    return `<div class="spell-card" style="background:rgba(20,12,5,0.7); border:1px solid ${col}40; border-left:3px solid ${col}; border-radius:8px; padding:14px; transition:transform 0.15s; cursor:default;" onmouseover="this.style.transform='translateY(-2px)'" onmouseout="this.style.transform=''">
      <div style="display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:8px;">
        <strong style="color:#e8d5a0; font-size:1em; font-family:Cinzel,serif;">${s.name}</strong>
        <span style="background:${col}22; color:${col}; font-size:0.72em; padding:2px 7px; border-radius:10px; white-space:nowrap; margin-left:8px;">${lvlLabel}</span>
      </div>
      <div style="color:${col}; font-size:0.75em; text-transform:capitalize; margin-bottom:8px; letter-spacing:0.5px;">${s.level_school}</div>
      ${s.casting_time ? `<div style="font-size:0.78em; color:#b8a060; margin-bottom:2px;"><span style="color:#888;">Cast:</span> ${s.casting_time}</div>` : ''}
      ${s.range ? `<div style="font-size:0.78em; color:#b8a060; margin-bottom:2px;"><span style="color:#888;">Range:</span> ${s.range}</div>` : ''}
      ${s.duration ? `<div style="font-size:0.78em; color:#b8a060; margin-bottom:8px;"><span style="color:#888;">Duration:</span> ${s.duration}</div>` : ''}
      ${s.desc ? `<div style="font-size:0.8em; color:#a09070; line-height:1.5; border-top:1px solid rgba(255,255,255,0.06); padding-top:8px; margin-top:4px;">${s.desc.substring(0,220)}${s.desc.length > 220 ? '…' : ''}</div>` : ''}
    </div>`;
  }).join('');
  
  // Add count display
  const countText = `<p style="color:var(--gold); margin-bottom:15px; font-family: 'Cinzel', serif;">${filtered.length} spells available to ${className.charAt(0).toUpperCase() + className.slice(1)}s</p>`;
  container.insertAdjacentHTML('beforebegin', countText);
}


